"""
UC (Unity Catalog) polymorphic Python UDTF code literal reading utilities.

This module handles reading and executing UC UDTF code literals from the wire format
for the analyze path.
"""

from typing import IO

from pyspark.errors import PySparkRuntimeError
from pyspark.serializers import SpecialLengths
from pyspark.worker_util import pickleSer


def read_uc_udtf_handler(infile: IO, length: int) -> type:
    """
    Read a UC UDTF code literal and return the handler class.

    This function handles the UC polymorphic UDTF case where the function is stored
    as a code literal (not pickled). It reads the code and handler name from the stream,
    executes the code, and returns the handler class.

    Args:
        infile: Input stream to read from
        length: The length marker already read from the stream (should be PYTHON_CODE_LITERAL)

    Returns:
        The handler class for the UDTF

    Raises:
        PySparkRuntimeError: If the code cannot be compiled or the handler is not found
    """
    if length != SpecialLengths.PYTHON_CODE_LITERAL:
        raise PySparkRuntimeError(
            errorClass="UDTF_EXEC_ERROR",
            messageParameters={
                "method_name": "read_uc_udtf_handler",
                "error": f"Expected PYTHON_CODE_LITERAL marker, got {length}.",
            },
        )

    # UC polymorphic UDTF - use _read_analyze_func_from_code_literal to get
    # (code, handler_name) tuple, then execute with type injection.
    code, handler_name = pickleSer._read_analyze_func_from_code_literal(infile)

    # LIMITATION: Users must import pyspark types inside the analyze() function body,
    # not at module level or inside class body. This ensures imports happen at
    # function execution time and are available in the local scope.
    try:
        exec(code)
    except Exception as e:
        raise PySparkRuntimeError(
            errorClass="UDTF_EXEC_ERROR",
            messageParameters={
                "method_name": "builtin.exec",
                "error": f"Cannot compile the code, due to {e}.",
            },
        )

    local_vars = locals()
    if handler_name not in local_vars:
        raise PySparkRuntimeError(
            errorClass="UDTF_EXEC_ERROR",
            messageParameters={
                "method_name": "builtin.exec",
                "error": f"After code compilation, cannot find handler {handler_name}.",
            },
        )

    return local_vars[handler_name]
